using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API.
/// Uses constructor injection for HttpClient and ILogger.
/// </summary>
[McpServerToolType]
public class JsonPlaceholderTools(HttpClient httpClient, ILogger<JsonPlaceholderTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a post by its numeric ID from the JSONPlaceholder API.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var response = await httpClient.GetAsync($"/posts/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, JsonOptions);
    }

    [McpServerTool, Description("List posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts by this user ID (optional)")] int? userId = null,
        [Description("Maximum number of posts to return (default 10)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"/posts?userId={userId.Value}" : "/posts";
        logger.LogInformation("Listing posts from {Url}", url);

        var posts = await httpClient.GetFromJsonAsync<JsonElement[]>(url, cancellationToken)
            ?? [];

        var result = posts.Take(limit).ToArray();
        return JsonSerializer.Serialize(result, JsonOptions);
    }

    [McpServerTool, Description("Search for users by name or username on the JSONPlaceholder API.")]
    public async Task<string> SearchUsers(
        [Description("Text to search for in user name or username")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching users for '{Query}'", query);
        var users = await httpClient.GetFromJsonAsync<JsonElement[]>("/users", cancellationToken)
            ?? [];

        var matches = users.Where(u =>
            (u.GetProperty("name").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) ?? false) ||
            (u.GetProperty("username").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) ?? false))
            .ToArray();

        return matches.Length > 0
            ? JsonSerializer.Serialize(matches, JsonOptions)
            : "No users found matching the query.";
    }
}

